hooks.command:
node -e "
const fs = require('fs');
const path = require('path');

const specPath = path.join(process.cwd(), 'docs', 'spec', 'SPEC.md');

if (!fs.existsSync(specPath)) {
  console.error('HOOK BLOCKED: docs/spec/SPEC.md does not exist.');
  console.error('Product specification is required before writing code.');
  console.error('Action: Return to product-lead to produce SPEC.md.');
  process.exit(2);
}

const content = fs.readFileSync(specPath, 'utf8');

if (!content.includes('Acceptance Criteria')) {
  console.error('HOOK BLOCKED: SPEC.md has no Acceptance Criteria section.');
  console.error('Every feature must have testable acceptance criteria before implementation.');
  console.error('Action: Return to product-lead to add acceptance criteria to SPEC.md.');
  process.exit(2);
}

const acMatches = content.match(/- \[ \]/g);
if (!acMatches || acMatches.length === 0) {
  console.error('HOOK BLOCKED: SPEC.md Acceptance Criteria section has no criteria items.');
  console.error('Add at least one testable criterion before writing code.');
  console.error('Action: Return to product-lead to populate acceptance criteria.');
  process.exit(2);
}

process.exit(0);
"
